package org.apache.commons.csv;
import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.Closeable;
import java.io.File;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.Reader;
import java.net.URL;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidStringAndFormat_returnsCSVParser() throws IOException {
        String input = "a,b,c\n1,2,3";
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // No exception thrown from Assertions.notNull
            assertionsMockedStatic.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).thenCallRealMethod();

            CSVParser parser = CSVParser.parse(input, format);

            assertNotNull(parser);
            assertEquals(format, getField(parser, "format"));
            assertFalse(parser.isClosed());
        }
    }

    @Test
    void testParse_withNullString_throwsNullPointerException() {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "string"))
                    .thenThrow(new NullPointerException("string"));

            NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(null, format));
            assertEquals("string", ex.getMessage());
        }
    }

    @Test
    void testParse_withNullFormat_throwsNullPointerException() {
        String input = "a,b,c";

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "format"))
                    .thenThrow(new NullPointerException("format"));

            NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(input, null));
            assertEquals("format", ex.getMessage());
        }
    }

    private Object getField(Object instance, String fieldName) {
        try {
            var field = instance.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.get(instance);
        } catch (Exception e) {
            fail("Reflection failed for field: " + fieldName + " with exception: " + e);
            return null;
        }
    }
}
